create or replace function get_leaderboard(limit_count integer default 50, offset_count integer default 0) returns setof leaderboard_entries language sql security invoker as $$ select * from leaderboard_entries order by best_score desc, highest_stage desc, first_try_correct desc, wrong_answer_count asc, achieved_at asc limit greatest(limit_count,0) offset greatest(offset_count,0) $$;
create or replace function get_my_rank() returns integer language sql security invoker as $$ select rank::integer from (select user_id, row_number() over(order by best_score desc, highest_stage desc, first_try_correct desc, wrong_answer_count asc, achieved_at asc) rank from leaderboard_entries) ranked where user_id = auth.uid() $$;
create or replace function update_leaderboard_best(p_score integer, p_stage integer, p_first_try integer, p_wrong integer) returns leaderboard_entries language plpgsql security definer set search_path = public as $$ declare n leaderboard_entries; p text; begin select nickname into p from profiles where user_id=auth.uid(); insert into leaderboard_entries(user_id,nickname,best_score,highest_stage,first_try_correct,wrong_answer_count) values(auth.uid(),coalesce(p,'플레이어'),p_score,p_stage,p_first_try,p_wrong) on conflict(user_id) do update set nickname=excluded.nickname,best_score=excluded.best_score,highest_stage=excluded.highest_stage,first_try_correct=excluded.first_try_correct,wrong_answer_count=excluded.wrong_answer_count,updated_at=now() where (excluded.best_score,excluded.highest_stage,excluded.first_try_correct,-excluded.wrong_answer_count) > (leaderboard_entries.best_score,leaderboard_entries.highest_stage,leaderboard_entries.first_try_correct,-leaderboard_entries.wrong_answer_count); select * into n from leaderboard_entries where user_id=auth.uid(); return n; end $$;
create or replace function submit_game_result(result_payload jsonb) returns jsonb language plpgsql security definer set search_path=public as $$ declare n leaderboard_entries; begin select update_leaderboard_best((result_payload->>'total_score')::integer,(result_payload->>'cleared_stages')::integer,coalesce((result_payload->>'first_try_correct')::integer,0),coalesce((result_payload->>'wrong_answer_count')::integer,0)) into n; return to_jsonb(n); end $$;
revoke all on function update_leaderboard_best(integer,integer,integer,integer) from public; grant execute on function update_leaderboard_best(integer,integer,integer,integer) to authenticated; grant execute on function submit_game_result(jsonb) to authenticated; grant execute on function get_leaderboard(integer,integer) to authenticated; grant execute on function get_my_rank() to authenticated;
